// ---- WorkManager for Background Tasks ----
// Dependencies:
// implementation("androidx.work:work-runtime-ktx:2.9.0")

// ---- Worker classes ----

// ---- Basic Worker ----
class DataSyncWorker(
    context: Context,
    params: WorkerParameters
) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        return try {
            // Simulate data sync
            delay(2000)
            println("Data synced successfully")
            Result.success()
        } catch (e: Exception) {
            println("Sync failed: ${e.message}")
            Result.retry()
        }
    }
}

// ---- Worker with input data ----
class DownloadWorker(
    context: Context,
    params: WorkerParameters
) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        val url = inputData.getString("url") ?: return Result.failure()
        val filename = inputData.getString("filename") ?: return Result.failure()

        return try {
            // Simulate download
            delay(3000)
            println("Downloaded $url to $filename")

            val outputData = workDataOf(
                "downloadedFile" to filename,
                "size" to 1024
            )
            Result.success(outputData)
        } catch (e: Exception) {
            Result.retry()
        }
    }
}

// ---- Worker with progress ----
class ProgressWorker(
    context: Context,
    params: WorkerParameters
) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        val total = 100
        for (i in 0..total) {
            if (isStopped) {
                return Result.failure()
            }
            setProgress(workDataOf("progress" to i))
            delay(50)
        }
        return Result.success()
    }
}

// ---- Worker with constraints ----
class ConstrainedWorker(
    context: Context,
    params: WorkerParameters
) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        println("Working with constraints satisfied")
        delay(1000)
        return Result.success()
    }
}

// ---- Periodic worker ----
class PeriodicSyncWorker(
    context: Context,
    params: WorkerParameters
) : CoroutineWorker(context, params) {
    override suspend fun doWork(): Result {
        println("Periodic sync running at ${System.currentTimeMillis()}")
        return Result.success()
    }
}

// ---- WorkManager setup ----
class WorkManagerHelper(
    private val context: Context
) {
    private val workManager = WorkManager.getInstance(context)

    // ---- One-time work ----
    fun enqueueDataSync() {
        val work = OneTimeWorkRequestBuilder<DataSyncWorker>()
            .setConstraints(
                Constraints.Builder()
                    .setRequiredNetworkType(NetworkType.CONNECTED)
                    .build()
            )
            .addTag("sync")
            .build()

        workManager.enqueue(work)
    }

    // ---- Work with input data ----
    fun enqueueDownload(url: String, filename: String) {
        val inputData = workDataOf(
            "url" to url,
            "filename" to filename
        )

        val work = OneTimeWorkRequestBuilder<DownloadWorker>()
            .setInputData(inputData)
            .setConstraints(
                Constraints.Builder()
                    .setRequiredNetworkType(NetworkType.CONNECTED)
                    .build()
            )
            .addTag("download")
            .build()

        workManager.enqueue(work)
    }

    // ---- Work with progress ----
    fun enqueueProgressWork() {
        val work = OneTimeWorkRequestBuilder<ProgressWorker>()
            .setConstraints(
                Constraints.Builder()
                    .setRequiresBatteryNotLow(true)
                    .build()
            )
            .addTag("progress")
            .build()

        workManager.enqueue(work)

        // Observe progress
        workManager.getWorkInfoByIdLiveData(work.id)
            .observeForever { info ->
                if (info != null && info.state == WorkInfo.State.RUNNING) {
                    val progress = info.progress.getInt("progress", 0)
                    println("Progress: $progress%")
                }
            }
    }

    // ---- Periodic work ----
    fun enqueuePeriodicSync() {
        val constraints = Constraints.Builder()
            .setRequiredNetworkType(NetworkType.CONNECTED)
            .build()

        val work = PeriodicWorkRequestBuilder<PeriodicSyncWorker>(
            repeatInterval = 15,
            repeatIntervalTimeUnit = TimeUnit.MINUTES
        )
            .setConstraints(constraints)
            .addTag("periodic")
            .build()

        workManager.enqueueUniquePeriodicWork(
            "periodic_sync",
            ExistingPeriodicWorkPolicy.KEEP,
            work
        )
    }

    // ---- Cancel work ----
    fun cancelAllWork() {
        workManager.cancelAllWork()
    }

    fun cancelWorkByTag(tag: String) {
        workManager.cancelAllWorkByTag(tag)
    }

    // ---- Get work status ----
    fun observeWorkStatus() {
        workManager.getWorkInfosForTagLiveData("sync")
            .observeForever { workInfos ->
                if (workInfos != null) {
                    for (info in workInfos) {
                        println("Work: ${info.state}")
                    }
                }
            }
    }

    // ---- Chained work ----
    fun enqueueChainedWork() {
        val work1 = OneTimeWorkRequestBuilder<DataSyncWorker>()
            .addTag("step1")
            .build()

        val work2 = OneTimeWorkRequestBuilder<DownloadWorker>()
            .setInputData(workDataOf(
                "url" to "https://example.com/file",
                "filename" to "file.txt"
            ))
            .addTag("step2")
            .build()

        workManager
            .beginWith(work1)
            .then(work2)
            .enqueue()
    }
}

// ---- ViewModel with WorkManager ----
@HiltViewModel
class WorkManagerViewModel @Inject constructor(
    private val workManagerHelper: WorkManagerHelper
) : ViewModel() {
    private val _workStatus = MutableStateFlow<Map<String, WorkInfo.State>>(emptyMap())
    val workStatus: StateFlow<Map<String, WorkInfo.State>> = _workStatus.asStateFlow()

    fun startSync() {
        workManagerHelper.enqueueDataSync()
    }

    fun startDownload(url: String, filename: String) {
        workManagerHelper.enqueueDownload(url, filename)
    }

    fun startPeriodicSync() {
        workManagerHelper.enqueuePeriodicSync()
    }

    fun cancelAll() {
        workManagerHelper.cancelAllWork()
    }

    fun cancelSync() {
        workManagerHelper.cancelWorkByTag("sync")
    }
}

// ---- UI ----
@Composable
fun WorkManagerScreen(
    viewModel: WorkManagerViewModel = hiltViewModel()
) {
    Scaffold(
        topBar = { TopAppBar { Text("WorkManager Demo") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Text("Background Tasks", style = MaterialTheme.typography.titleMedium)

            Button(
                onClick = { viewModel.startSync() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Start Data Sync")
            }

            Button(
                onClick = {
                    viewModel.startDownload(
                        "https://example.com/file",
                        "downloaded_file.txt"
                    )
                },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Start Download")
            }

            Button(
                onClick = { viewModel.startPeriodicSync() },
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Start Periodic Sync (15 min)")
            }

            Divider()

            Button(
                onClick = { viewModel.cancelSync() },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.error
                )
            ) {
                Text("Cancel Sync")
            }

            Button(
                onClick = { viewModel.cancelAll() },
                modifier = Modifier.fillMaxWidth(),
                colors = ButtonDefaults.buttonColors(
                    containerColor = MaterialTheme.colorScheme.error
                )
            ) {
                Text("Cancel All Work")
            }
        }
    }
}

